module multi_pipe_8bit
(
    input clk,
    input rst_n,
    input mul_en_in,
    input mul_a,
    input mul_b,
    output mul_en_out,
    output mul_out
);
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) mul_en_out_reg <= {8{1'b0}};
    else        mul_en_out_reg <= {mul_en_out_reg[6:0], mul_en_in};
end
assign mul_en_out = mul_en_out_reg[7];
reg [7:0] mul_a_reg, mul_b_reg;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_a_reg <= 8'b0;
        mul_b_reg <= 8'b0;
    end
    else if (mul_en_out_reg[0]) begin
        mul_a_reg <= mul_a;
        mul_b_reg <= mul_b;
    end
end
wire [7:0] temp0, temp1, temp2, temp3, temp4, temp5, temp6, temp7;
assign temp0 = mul_en_out_reg[0] ? (mul_b_reg[0] ? mul_a : 8'b0) : 8'b0;
assign temp1 = mul_en_out_reg[1] ? (mul_b_reg[1] ? mul_a : 8'b0) : 8'b0;
assign temp2 = mul_en_out_reg[2] ? (mul_b_reg[2] ? mul_a : 8'b0) : 8'b0;
assign temp3 = mul_en_out_reg[3] ? (mul_b_reg[3] ? mul_a : 8'b0) : 8'b0;
assign temp4 = mul_en_out_reg[4] ? (mul_b_reg[4] ? mul_a : 8'b0) : 8'b0;
assign temp5 = mul_en_out_reg[5] ? (mul_b_reg[5] ? mul_a : 8'b0) : 8'b0;
assign temp6 = mul_en_out_reg[6] ? (mul_b_reg[6] ? mul_a : 8'b0) : 8'b0;
assign temp7 = mul_en_out_reg[7] ? (mul_b_reg[7] ? mul_a : 8'b0) : 8'b0;
reg [14:0] sum0, sum1, sum2, sum3, sum4, sum5, sum6;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        sum0 <= 15'b0;
        sum1 <= 15'b0;
        sum2 <= 15'b0;
        sum3 <= 15'b0;
        sum4 <= 15'b0;
        sum5 <= 15'b0;
        sum6 <= 15'b0;
    end
    else if (mul_en_out_reg[1]) begin
        sum0 <= temp0 + (temp1 << 1);
        sum1 <= temp2 + (temp3 << 1) + sum0[7:0];
        sum2 <= temp4 + (temp5 << 1) + sum1[7:0];
        sum3 <= temp6 + (temp7 << 1) + sum2[7:0];
    end
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) mul_out_reg <= 16'b0;
    else        mul_out_reg <= mul_out_reg[7:0] + sum3;
end
assign mul_out = mul_en_out ? mul_out_reg : 16'b0;
endmodule
